1	package com.mzfuture.entire.checkpoint.transcript.format;
2	
3	import com.fasterxml.jackson.databind.JsonNode;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptDTO;
6	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptMetaDTO;
7	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileChangeSummaryDTO;
8	import com.mzfuture.entire.checkpoint.dto.response.TranscriptMessageViewDTO;
9	import com.mzfuture.entire.checkpoint.dto.response.TranscriptToolUseDTO;
10	import com.mzfuture.entire.checkpoint.transcript.TranscriptFormat;
11	import com.mzfuture.entire.checkpoint.transcript.support.AnthropicContentBlocks;
12	import com.mzfuture.entire.checkpoint.transcript.support.FilePathExtractor;
13	import org.springframework.stereotype.Component;
14	
15	import java.util.ArrayList;
16	import java.util.Collections;
17	import java.util.HashMap;
18	import java.util.LinkedHashMap;
19	import java.util.List;
20	import java.util.Locale;
21	import java.util.Map;
22	
23	/// Claude Code NDJSON: each non-empty line is `{type, message, ...}`. Keeps only
24	/// `type == "user"` and `type == "assistant"`. Merges streaming duplicates by
25	/// `message.id`. Folds `tool_result` content back into the matching prior tool_use.
26	@Component
27	public class ClaudeCodeFormat implements TranscriptFormat {
28	
29	    private static final String NAME = "claude-code-ndjson";
30	
31	    private final ObjectMapper objectMapper = new ObjectMapper();
32	
33	    @Override public String name() { return NAME; }
34	    @Override public int priority() { return 80; }
35	
36	    @Override
37	    public boolean matches(String raw) {
38	        for (String line : raw.split("\\R")) {
39	            String t = line.trim();
40	            if (t.isEmpty()) continue;
41	            try {
42	                JsonNode n = objectMapper.readTree(t);
43	                if (!n.isObject()) continue;
44	                JsonNode type = n.get("type");
45	                JsonNode message = n.get("message");
46	                if (type == null || !type.isTextual()) continue;
47	                if (message == null || !message.isObject()) continue;
48	                String s = type.asText();
49	                if ("user".equals(s) || "assistant".equals(s)) return true;
50	            } catch (Exception e) {
51	                continue;
52	            }
53	        }
54	        return false;
55	    }
56	
57	    @Override
58	    public NormalizedTranscriptDTO parse(String raw, long rawBytesLength, List<String> warnings) throws Exception {
59	        // Streaming dedup: order-preserving map from message.id -> index in messages.
60	        // When a new id arrives, the previous id is already merged.
61	        Map<String, Integer> idToIndex = new HashMap<>();
62	        List<TranscriptMessageViewDTO> messages = new ArrayList<>();
63	        int stepsCount = 0;
64	
65	        for (String rawLine : raw.split("\\R")) {
66	            String line = rawLine.trim();
67	            if (line.isEmpty()) continue;
68	            JsonNode n;
69	            try {
70	                n = objectMapper.readTree(line);
71	            } catch (Exception e) {
72	                continue;
73	            }
74	            String type = textOrNull(n, "type");
75	            if (!"user".equals(type) && !"assistant".equals(type)) continue;
76	            JsonNode message = n.path("message");
77	            String messageId = textOrNull(message, "id");
78	
79	            if (messageId != null && idToIndex.containsKey(messageId)) {
80	                int idx = idToIndex.get(messageId);
81	                mergeInto(messages.get(idx), n);
82	            } else {
83	                TranscriptMessageViewDTO mv = buildMessage(n, type);
84	                messages.add(mv);
85	                if (messageId != null) idToIndex.put(messageId, messages.size() - 1);
86	                if ("user".equalsIgnoreCase(mv.getRole())) stepsCount++;
87	            }
88	        }
89	
90	        // Note on tool_result folding: when a user line carries tool_result content blocks,
91	        // we could backfill the matching assistant tool_use.output. We don't, because
92	        // `buildMessage` already folded the tool_result text into the user message's `text`
93	        // field. The result is visible in the user turn; matching it back to a tool card on
94	        // a prior assistant turn is a follow-up enhancement.
95	
96	        List<TranscriptFileChangeSummaryDTO> fileChanges = buildFileChanges(messages);
97	
98	        NormalizedTranscriptDTO dto = new NormalizedTranscriptDTO();
99	        dto.setSchemaVersion(1);
100	        NormalizedTranscriptMetaDTO meta = new NormalizedTranscriptMetaDTO();
101	        meta.setSourceFormat(NAME);
102	        meta.setRawBytesLength(rawBytesLength);
103	        if (!warnings.isEmpty()) meta.setWarnings(new ArrayList<>(warnings));
104	        dto.setMeta(meta);
105	        dto.setStepsCount(stepsCount);
106	        dto.setFileChanges(fileChanges);
107	        dto.setMessages(messages);
108	        return dto;
109	    }
110	
111	    private TranscriptMessageViewDTO buildMessage(JsonNode root, String type) {
112	        JsonNode message = root.path("message");
113	        JsonNode content = message.path("content");
114	
115	        TranscriptMessageViewDTO mv = new TranscriptMessageViewDTO();
116	        mv.setId(textOrNull(message, "id"));
117	        mv.setRole("user".equals(type) ? "user" : "assistant");
118	        mv.setText(AnthropicContentBlocks.extractText(content));
119	        mv.setReasoning(AnthropicContentBlocks.extractReasoning(content));
120	
121	        List<TranscriptToolUseDTO> tools = new ArrayList<>();
122	        for (AnthropicContentBlocks.ToolUseEntry tu : AnthropicContentBlocks.extractToolUses(content)) {
123	            TranscriptToolUseDTO dto = new TranscriptToolUseDTO();
124	            dto.setCallID(tu.id());
125	            dto.setTool(tu.name());
126	            dto.setInput(tu.input());
127	            tools.add(dto);
128	        }
129	        mv.setTools(tools);
130	        mv.setToolsCount(tools.size());
131	        return mv;
132	    }
133	
134	    private void mergeInto(TranscriptMessageViewDTO existing, JsonNode newLine) {
135	        JsonNode message = newLine.path("message");
136	        JsonNode content = message.path("content");
137	        if (content == null || content.isNull() || content.isMissingNode()) return;
138	
139	        // Re-extract text and merge with existing.
140	        String newText = AnthropicContentBlocks.extractText(content);
141	        if (!newText.isEmpty()) {
142	            String cur = existing.getText() == null ? "" : existing.getText();
143	            if (!cur.contains(newText)) {
144	                existing.setText(cur.isEmpty() ? newText : cur + "\n" + newText);
145	            }
146	        }
147	
148	        // Append new tool_use blocks (dedupe by id).
149	        for (AnthropicContentBlocks.ToolUseEntry tu : AnthropicContentBlocks.extractToolUses(content)) {
150	            boolean already = existing.getTools() != null && existing.getTools().stream()
151	                    .anyMatch(t -> tu.id().equals(t.getCallID()));
152	            if (!already) {
153	                TranscriptToolUseDTO dto = new TranscriptToolUseDTO();
154	                dto.setCallID(tu.id());
155	                dto.setTool(tu.name());
156	                dto.setInput(tu.input());
157	                if (existing.getTools() == null) existing.setTools(new ArrayList<>());
158	                existing.getTools().add(dto);
159	            }
160	        }
161	        if (existing.getTools() != null) {
162	            existing.setToolsCount(existing.getTools().size());
163	        }
164	    }
165	
166	    private List<TranscriptFileChangeSummaryDTO> buildFileChanges(List<TranscriptMessageViewDTO> messages) {
167	        List<PathDelta> raw = new ArrayList<>();
168	        for (TranscriptMessageViewDTO msg : messages) {
169	            if (msg.getTools() == null) continue;
170	            for (TranscriptToolUseDTO tu : msg.getTools()) {
171	                String path = FilePathExtractor.extract(tu.getInput());
172	                if (path == null) continue;
173	                int[] d = estimateDelta(tu);
174	                if (d[0] == 0 && d[1] == 0) continue;
175	                raw.add(new PathDelta(path, d[0], d[1]));
176	            }
177	        }
178	        if (raw.isEmpty()) return Collections.emptyList();
179	        List<String> distinct = raw.stream().map(p -> p.path).distinct().toList();
180	        String dirPrefix = sharedDirectoryPrefix(distinct);
181	        Map<String, int[]> merged = new LinkedHashMap<>();
182	        for (PathDelta pd : raw) {
183	            String key = toRelative(pd.path, dirPrefix);
184	            merged.compute(key, (k, v) -> {
185	                if (v == null) return new int[]{pd.additions, pd.deletions};
186	                v[0] += pd.additions; v[1] += pd.deletions;
187	                return v;
188	            });
189	        }
190	        List<TranscriptFileChangeSummaryDTO> out = new ArrayList<>();
191	        for (Map.Entry<String, int[]> e : merged.entrySet()) {
192	            TranscriptFileChangeSummaryDTO s = new TranscriptFileChangeSummaryDTO();
193	            s.setFile(e.getKey());
194	            s.setAdditions(e.getValue()[0]);
195	            s.setDeletions(e.getValue()[1]);
196	            out.add(s);
197	        }
198	        return out;
199	    }
200	
201	    private static int[] estimateDelta(TranscriptToolUseDTO tu) {
202	        String lower = tu.getTool() == null ? "" : tu.getTool().toLowerCase(Locale.ROOT);
203	        JsonNode in = tu.getInput();
204	        if (in == null || !in.isObject()) return new int[]{0, 0};
205	        if (lower.equals("edit") || lower.equals("strreplace") || lower.equals("search_replace")
206	                || lower.equals("replace") || lower.equals("notebookedit")) {
207	            String o = in.has("old_string") && in.get("old_string").isTextual() ? in.get("old_string").asText("") : "";
208	            String n = in.has("new_string") && in.get("new_string").isTextual() ? in.get("new_string").asText("") : "";
209	            int oldLines = countLines(o), newLines = countLines(n);
210	            return new int[]{Math.max(0, newLines - oldLines), Math.max(0, oldLines - newLines)};
211	        }
212	        if (lower.equals("write") || lower.equals("apply_patch")) {
213	            String c = "";
214	            if (in.has("content") && in.get("content").isTextual()) c = in.get("content").asText("");
215	            else if (in.has("contents") && in.get("contents").isTextual()) c = in.get("contents").asText("");
216	            return new int[]{countLines(c), 0};
217	        }
218	        return new int[]{0, 0};
219	    }
220	
221	    private static int countLines(String s) {
222	        if (s == null || s.isEmpty()) return 0;
223	        int n = 1;
224	        for (int i = 0; i < s.length(); i++) if (s.charAt(i) == '\n') n++;
225	        return n;
226	    }
227	
228	    private static String sharedDirectoryPrefix(List<String> paths) {
229	        if (paths.isEmpty()) return "";
230	        if (paths.size() == 1) {
231	            String p = paths.get(0);
