1	package com.mzfuture.entire.checkpoint.transcript.format;
2	
3	import com.fasterxml.jackson.databind.JsonNode;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptDTO;
6	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptMetaDTO;
7	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileChangeSummaryDTO;
8	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileDiffDTO;
9	import com.mzfuture.entire.checkpoint.dto.response.TranscriptMessageViewDTO;
10	import com.mzfuture.entire.checkpoint.dto.response.TranscriptToolUseDTO;
11	import com.mzfuture.entire.checkpoint.transcript.TranscriptFormat;
12	import org.springframework.stereotype.Component;
13	
14	import java.util.ArrayList;
15	import java.util.LinkedHashMap;
16	import java.util.List;
17	import java.util.Map;
18	
19	/// OpenCode single JSON: `{info: {...}, messages: [{info, parts, summary}, ...]}`.
20	/// Detection: trimmed text parses as a single JSON object with `info` AND `messages` (array).
21	@Component
22	public class OpenCodeFormat implements TranscriptFormat {
23	
24	    private static final String NAME = "opencode-json";
25	
26	    private final ObjectMapper objectMapper = new ObjectMapper();
27	
28	    @Override public String name() { return NAME; }
29	    @Override public int priority() { return 100; }
30	
31	    @Override
32	    public boolean matches(String raw) {
33	        try {
34	            JsonNode root = objectMapper.readTree(raw);
35	            return root.isObject()
36	                    && root.has("info")
37	                    && root.has("messages")
38	                    && root.get("messages").isArray();
39	        } catch (Exception e) {
40	            return false;
41	        }
42	    }
43	
44	    @Override
45	    public NormalizedTranscriptDTO parse(String raw, long rawBytesLength, List<String> warnings) throws Exception {
46	        JsonNode root = objectMapper.readTree(raw);
47	        JsonNode info = root.path("info");
48	        String title = textOrNull(info, "title");
49	        String projectRoot = textOrNull(info, "directory");
50	
51	        Map<String, int[]> fileChangeMap = new LinkedHashMap<>();
52	        List<TranscriptMessageViewDTO> messageViews = new ArrayList<>();
53	        int stepsCount = 0;
54	
55	        JsonNode messages = root.path("messages");
56	        if (!messages.isArray()) {
57	            warnings.add("OpenCode: missing messages array");
58	        } else {
59	            for (JsonNode msg : messages) {
60	                JsonNode infoN = msg.path("info");
61	                String roleStr = textOrNull(infoN, "role");
62	                boolean isUser = "user".equalsIgnoreCase(roleStr);
63	                if (isUser) stepsCount++;
64	
65	                JsonNode parts = msg.path("parts");
66	                StringBuilder textParts = new StringBuilder();
67	                String reasoning = null;
68	                List<TranscriptToolUseDTO> tools = new ArrayList<>();
69	
70	                if (parts.isArray()) {
71	                    for (JsonNode p : parts) {
72	                        String type = textOrNull(p, "type");
73	                        if ("text".equals(type)) {
74	                            String t = p.has("text") ? p.get("text").asText("") : "";
75	                            if (textParts.length() > 0) textParts.append('\n');
76	                            textParts.append(t);
77	                        } else if ("reasoning".equals(type)) {
78	                            reasoning = p.has("text") ? p.get("text").asText("") : null;
79	                        } else if ("tool".equals(type)) {
80	                            TranscriptToolUseDTO tu = new TranscriptToolUseDTO();
81	                            tu.setCallID(textOrNull(p, "callID"));
82	                            tu.setTool(textOrNull(p, "tool"));
83	                            JsonNode state = p.path("state");
84	                            if (!state.isMissingNode() && !state.isNull()) {
85	                                if (state.has("input")) tu.setInput(state.get("input"));
86	                                if (state.has("output")) tu.setOutput(state.get("output"));
87	                                tu.setTitle(textOrNull(state, "title"));
88	                            }
89	                            tools.add(tu);
90	                        }
91	                    }
92	                }
93	
94	                JsonNode summary = infoN.path("summary");
95	                List<TranscriptFileDiffDTO> diffs = null;
96	                if (summary.has("diffs") && summary.get("diffs").isArray()) {
97	                    diffs = new ArrayList<>();
98	                    for (JsonNode d : summary.get("diffs")) {
99	                        TranscriptFileDiffDTO fd = new TranscriptFileDiffDTO();
100	                        String file = d.has("file") ? d.get("file").asText("") : "";
101	                        fd.setFile(stripProjectRoot(file, projectRoot));
102	                        fd.setBefore(textOrNull(d, "before"));
103	                        fd.setAfter(textOrNull(d, "after"));
104	                        int add = d.has("additions") ? d.get("additions").asInt() : 0;
105	                        int del = d.has("deletions") ? d.get("deletions").asInt() : 0;
106	                        fd.setAdditions(add);
107	                        fd.setDeletions(del);
108	                        diffs.add(fd);
109	                        String rel = fd.getFile();
110	                        fileChangeMap.compute(rel, (k, v) -> {
111	                            if (v == null) return new int[]{add, del};
112	                            v[0] += add; v[1] += del;
113	                            return v;
114	                        });
