1	package com.mzfuture.entire.checkpoint.transcript.support;
2	
3	import com.fasterxml.jackson.databind.JsonNode;
4	
5	import java.util.ArrayList;
6	import java.util.List;
7	
8	/// Parses Anthropic-Messages-API-style content nodes (string or array of typed blocks).
9	/// Used by Cursor, Claude Code, and Droid transcript formats.
10	public final class AnthropicContentBlocks {
11	
12	    private AnthropicContentBlocks() {}
13	
14	    /// Concatenated visible text from all `text` blocks. Returns empty string if no text blocks.
15	    public static String extractText(JsonNode content) {
16	        StringBuilder sb = new StringBuilder();
17	        if (content == null) return "";
18	        if (content.isTextual()) {
19	            return content.asText("");
20	        }
21	        if (content.isArray()) {
22	            for (JsonNode block : content) {
23	                if ("text".equals(textOrNull(block, "type"))) {
24	                    String t = block.has("text") ? block.get("text").asText("") : "";
25	                    if (sb.length() > 0) sb.append('\n');
26	                    sb.append(t);
27	                }
28	            }
29	        }
30	        return sb.toString().trim();
31	    }
32	
33	    /// Concatenated thinking text from all `thinking` blocks, or null if none present.
34	    public static String extractReasoning(JsonNode content) {
35	        StringBuilder sb = new StringBuilder();
36	        if (content == null || !content.isArray()) return null;
37	        for (JsonNode block : content) {
38	            if ("thinking".equals(textOrNull(block, "type"))) {
39	                String t = block.has("thinking") ? block.get("thinking").asText("") : "";
40	                if (sb.length() > 0) sb.append('\n');
41	                sb.append(t);
42	            }
43	        }
44	        return sb.length() == 0 ? null : sb.toString().trim();
45	    }
46	
47	    /// Tool-use blocks. Each block becomes a record with id, name, input. The `id` and `name`
48	    /// fall back to empty strings when missing so downstream code can still match by call id.
49	    public static List<ToolUseEntry> extractToolUses(JsonNode content) {
50	        List<ToolUseEntry> out = new ArrayList<>();
51	        if (content == null || !content.isArray()) return out;
52	        for (JsonNode block : content) {
53	            if ("tool_use".equals(textOrNull(block, "type"))) {
54	                String id = firstNonEmpty(textOrNull(block, "id"), textOrNull(block, "call_id"));
55	                String name = textOrNull(block, "name");
56	                JsonNode input = block.has("input") && !block.get("input").isNull()
57	                        ? block.get("input") : null;
58	                out.add(new ToolUseEntry(id == null ? "" : id,
59	                        name == null ? "" : name, input));
60	            }
61	        }
62	        return out;
63	    }
64	
65	    /// Tool-result blocks. `entries` have the tool_use_id, the result content as a string,
66	    /// and the `is_error` flag. Used to backfill `tool_use.output`.
67	    public static List<ToolResultEntry> extractToolResults(JsonNode content) {
68	        List<ToolResultEntry> out = new ArrayList<>();
69	        if (content == null || !content.isArray()) return out;
70	        for (JsonNode block : content) {
71	            if ("tool_result".equals(textOrNull(block, "type"))) {
72	                String id = textOrNull(block, "tool_use_id");
73	                JsonNode r = block.get("content");
74	                String text = r == null ? "" : (r.isTextual() ? r.asText("") : r.toString());
75	                boolean isError = block.has("is_error") && block.get("is_error").asBoolean(false);
76	                out.add(new ToolResultEntry(id == null ? "" : id, text, isError));
77	            }
78	        }
79	        return out;
80	    }
81	
82	    private static String textOrNull(JsonNode node, String field) {
83	        if (node == null || !node.has(field) || node.get(field).isNull()) return null;
84	        JsonNode v = node.get(field);
85	        if (v.isValueNode()) return v.asText();
86	        return null;
87	    }
88	
89	    private static String firstNonEmpty(String a, String b) {
90	        if (a != null && !a.isEmpty()) return a;
91	        if (b != null && !b.isEmpty()) return b;
92	        return a != null ? a : b;
