36	import java.util.stream.Collectors;
37	
38	/// Reads file content at a given revision and walks commits (for checkpoint sync).
39	@Slf4j
40	@Component
41	public class CheckpointGitReader {
42	
43	    private final GitOperationService gitOperationService;
44	
45	    public CheckpointGitReader(GitOperationService gitOperationService) {
46	        this.gitOperationService = gitOperationService;
47	    }
48	
49	    /// Open repository with working directory, explicitly setGitDir(.git) + setWorkTree(repoDir) to prevent create(repoDir) from being treated as bare, which would cause resolve() to return null for packed-refs.
50	    private static Repository openRepository(File repoDir) throws IOException {
51	        File gitDir = new File(repoDir, ".git");
52	        if (gitDir.isDirectory()) {
53	            return new FileRepositoryBuilder().setGitDir(gitDir).setWorkTree(repoDir).build();
54	        }
55	        return FileRepositoryBuilder.create(repoDir);
56	    }
57	
58	    /// Read file content at the given revision (commit SHA or HEAD).
59	    /// @param repoId repository id
60	    /// @param revision commit SHA or "HEAD"
61	    /// @param path path relative to repo root, e.g. "1a/d322329de8/metadata.json"
62	    /// @return content as string, or empty if file not found
63	    public Optional<String> getFileContent(Long repoId, String revision, String path) {
64	        File repoDir = new File(gitOperationService.getLocalRepositoryPath(repoId));
65	        if (!repoDir.exists() || !new File(repoDir, ".git").exists()) {
66	            return Optional.empty();
67	        }
68	        try (Repository repository = openRepository(repoDir)) {
69	            ObjectId revId = repository.resolve(revision);
70	            if (revId == null) {
71	                return Optional.empty();
72	            }
73	            try (RevWalk walk = new RevWalk(repository)) {
74	                RevCommit commit = walk.parseCommit(revId);
75	                RevTree tree = commit.getTree();
76	                try (ObjectReader reader = repository.newObjectReader();
77	                     TreeWalk treeWalk = TreeWalk.forPath(reader, path, tree)) {
78	                    if (treeWalk == null) {
79	                        return Optional.empty();
80	                    }
81	                    ObjectId blobId = treeWalk.getObjectId(0);
82	                    ObjectLoader loader = reader.open(blobId);
83	                    byte[] bytes = loader.getBytes();
84	                    return Optional.of(new String(bytes, StandardCharsets.UTF_8));
85	                }
86	            }
87	        } catch (IOException e) {
88	            log.warn("Read file at revision failed: repoId={}, revision={}, path={}, error={}",
89	                    repoId, revision, path, e.getMessage());
90	            return Optional.empty();
91	        }
92	    }
93	
94	    /// Walk commits from the given branch ref (refs/heads/branchName) toward history; stop at stopAtCommitSha (exclusive) or root.
95	    /// @param repoId repository id
96	    /// @param branchName short branch name, e.g. "main", "entire/checkpoints/v1"
97	    /// @param stopAtCommitSha optional commit SHA to stop before (exclusive)
98	    /// @return list of commits (newest first)
99	    public List<CommitInfo> walkCommitsFromBranch(Long repoId, String branchName, String stopAtCommitSha) {
100	        List<CommitInfo> result = new ArrayList<>();
101	        File repoDir = new File(gitOperationService.getLocalRepositoryPath(repoId));
102	        if (!repoDir.exists() || !new File(repoDir, ".git").exists()) {
103	            return result;
104	        }
105	        String refName = branchName.startsWith("refs/heads/") ? branchName : "refs/heads/" + branchName;
106	        try (Repository repository = openRepository(repoDir);
107	             RevWalk walk = new RevWalk(repository)) {
108	            ObjectId branchHead = resolveBranchToCommit(repository, refName);
109	            if (branchHead == null) {
110	                return result;
111	            }
112	            walk.markStart(walk.parseCommit(branchHead));
113	            ObjectId stopId = (stopAtCommitSha != null && !stopAtCommitSha.isEmpty())
114	                    ? repository.resolve(stopAtCommitSha) : null;
115	            for (RevCommit c : walk) {
116	                if (stopId != null && c.getId().equals(stopId)) {
117	                    break;
118	                }
119	                String authorName = getAuthorName(c);
120	                long commitTimeMs = toCommitTimeMs(c);
121	                result.add(new CommitInfo(c.getName(), c.getFullMessage(), authorName, commitTimeMs));
122	            }
123	        } catch (IOException e) {
124	            log.warn("Walk commits from branch failed: repoId={}, branch={}, error={}", repoId, branchName, e.getMessage());
125	        }
126	        return result;
127	    }
128	
129	    /// Convert RevCommit.getCommitTime() (seconds) to ms; fallback to current time if invalid.
130	    private static long toCommitTimeMs(RevCommit c) {
131	        int sec = c.getCommitTime();
132	        if (sec > 0) {
133	            return sec * 1000L;
134	        }
135	        return System.currentTimeMillis();
136	    }
137	
138	    private static String getAuthorName(RevCommit c) {
139	        PersonIdent ident = c.getAuthorIdent();
140	        return ident != null ? ident.getName() : null;
141	    }
142	
143	    /// List local branch short names (refs/heads/*).
144	    public List<String> listLocalBranchNames(Long repoId) {
145	        File repoDir = new File(gitOperationService.getLocalRepositoryPath(repoId));
146	        if (!repoDir.exists() || !new File(repoDir, ".git").exists()) {
147	            return Collections.emptyList();
148	        }
149	        try (Repository repository = openRepository(repoDir)) {
150	            RefDatabase refDb = repository.getRefDatabase();
151	            List<Ref> refs = refDb.getRefsByPrefix("refs/heads");
152	            return refs.stream()
153	                    .map(ref -> Repository.shortenRefName(ref.getName()))
154	                    .sorted()
155	                    .collect(Collectors.toList());
156	        } catch (IOException e) {
157	            log.warn("List local branches failed: repoId={}, error={}", repoId, e.getMessage());
158	            return Collections.emptyList();
159	        }
160	    }
161	
162	    /// Resolve a branch to commit SHA (for reading metadata from that branch). Uses refs/heads/branchName.
