1	package com.mzfuture.entire.checkpoint.transcript.format;
2	
3	import com.fasterxml.jackson.databind.JsonNode;
4	import com.fasterxml.jackson.databind.ObjectMapper;
5	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptDTO;
6	import com.mzfuture.entire.checkpoint.dto.response.NormalizedTranscriptMetaDTO;
7	import com.mzfuture.entire.checkpoint.dto.response.TranscriptFileChangeSummaryDTO;
8	import com.mzfuture.entire.checkpoint.dto.response.TranscriptMessageViewDTO;
9	import com.mzfuture.entire.checkpoint.dto.response.TranscriptToolUseDTO;
10	import com.mzfuture.entire.checkpoint.transcript.TranscriptFormat;
11	import com.mzfuture.entire.checkpoint.transcript.support.AnthropicContentBlocks;
12	import com.mzfuture.entire.checkpoint.transcript.support.FilePathExtractor;
13	import org.springframework.stereotype.Component;
14	
15	import java.util.ArrayList;
16	import java.util.Collections;
17	import java.util.LinkedHashMap;
18	import java.util.List;
19	import java.util.Locale;
20	import java.util.Map;
21	
22	/// Cursor NDJSON: each non-empty line is `{role: "user"|"assistant", message: {...}}`.
23	/// Detection: non-empty first line is a JSON object with `role ∈ {user, assistant}` and `message`.
24	@Component
25	public class CursorFormat implements TranscriptFormat {
26	
27	    private static final String NAME = "cursor-ndjson";
28	
29	    private final ObjectMapper objectMapper = new ObjectMapper();
30	
31	    @Override public String name() { return NAME; }
32	    @Override public int priority() { return 75; }
33	
34	    @Override
35	    public boolean matches(String raw) {
36	        for (String line : raw.split("\\R")) {
37	            String t = line.trim();
38	            if (t.isEmpty()) continue;
39	            try {
40	                JsonNode n = objectMapper.readTree(t);
41	                if (!n.isObject()) return false;
42	                JsonNode r = n.get("role");
43	                JsonNode m = n.get("message");
44	                if (r == null || !r.isTextual()) return false;
45	                if (m == null || !m.isObject()) return false;
46	                String role = r.asText();
47	                return "user".equalsIgnoreCase(role) || "assistant".equalsIgnoreCase(role);
48	            } catch (Exception e) {
49	                return false;
50	            }
51	        }
52	        return false;
53	    }
54	
55	    @Override
56	    public NormalizedTranscriptDTO parse(String raw, long rawBytesLength, List<String> warnings) throws Exception {
57	        List<String> lines = new ArrayList<>();
58	        for (String p : raw.split("\\R")) {
59	            String s = p.trim();
60	            if (!s.isEmpty()) lines.add(s);
61	        }
62	
63	        List<TranscriptMessageViewDTO> messageViews = new ArrayList<>();
64	        int stepsCount = 0;
65	        int toolUseCount = 0;
66	        for (String line : lines) {
67	            JsonNode n = objectMapper.readTree(line);
68	            TranscriptMessageViewDTO mv = parseLine(n);
69	            messageViews.add(mv);
70	            if ("user".equalsIgnoreCase(mv.getRole())) {
71	                stepsCount++;
72	            }
73	            toolUseCount += mv.getTools() == null ? 0 : mv.getTools().size();
74	        }
75	        if (toolUseCount == 0) {
76	            warnings.add("cursor: tool_use blocks absent; file_changes may be empty");
77	        }
78	
79	        List<TranscriptFileChangeSummaryDTO> fileChanges = buildFileChanges(messageViews);
80	
81	        NormalizedTranscriptDTO dto = new NormalizedTranscriptDTO();
82	        dto.setSchemaVersion(1);
83	        NormalizedTranscriptMetaDTO meta = new NormalizedTranscriptMetaDTO();
84	        meta.setSourceFormat(NAME);
85	        meta.setRawBytesLength(rawBytesLength);
86	        if (!warnings.isEmpty()) meta.setWarnings(new ArrayList<>(warnings));
87	        dto.setMeta(meta);
88	        dto.setStepsCount(stepsCount);
89	        dto.setFileChanges(fileChanges);
90	        dto.setMessages(messageViews);
91	        return dto;
92	    }
93	
94	    private TranscriptMessageViewDTO parseLine(JsonNode root) {
95	        String roleRaw = root.path("role").asText("");
96	        String role = "user".equalsIgnoreCase(roleRaw) ? "user" : "assistant";
97	        JsonNode message = root.path("message");
98	        JsonNode content = message.path("content");
99	
100	        TranscriptMessageViewDTO mv = new TranscriptMessageViewDTO();
101	        mv.setId("");
102	        mv.setRole(role);
103	        mv.setText(AnthropicContentBlocks.extractText(content));
104	
105	        List<TranscriptToolUseDTO> tools = new ArrayList<>();
106	        for (AnthropicContentBlocks.ToolUseEntry tu : AnthropicContentBlocks.extractToolUses(content)) {
107	            TranscriptToolUseDTO dto = new TranscriptToolUseDTO();
108	            dto.setCallID(tu.id());
109	            dto.setTool(tu.name());
110	            dto.setInput(tu.input());
111	            tools.add(dto);
112	        }
113	        mv.setTools(tools);
114	        mv.setToolsCount(tools.size());
115	        return mv;
116	    }
117	
118	    private List<TranscriptFileChangeSummaryDTO> buildFileChanges(List<TranscriptMessageViewDTO> messages) {
119	        List<PathDelta> raw = new ArrayList<>();
120	        for (TranscriptMessageViewDTO msg : messages) {
121	            if (msg.getTools() == null) continue;
122	            for (TranscriptToolUseDTO tu : msg.getTools()) {
123	                String path = FilePathExtractor.extract(tu.getInput());
124	                if (path == null || path.isBlank()) continue;
125	                int[] d = estimateDelta(tu);
126	                raw.add(new PathDelta(path, d[0], d[1]));
127	            }
128	        }
129	        if (raw.isEmpty()) return Collections.emptyList();
130	        List<String> distinct = raw.stream().map(p -> p.path).distinct().toList();
131	        String dirPrefix = sharedDirectoryPrefix(distinct);
132	        Map<String, int[]> merged = new LinkedHashMap<>();
133	        for (PathDelta pd : raw) {
134	            String key = toRelative(pd.path, dirPrefix);
135	            merged.compute(key, (k, v) -> {
136	                if (v == null) return new int[]{pd.additions, pd.deletions};
137	                v[0] += pd.additions; v[1] += pd.deletions;
138	                return v;
