22	/// Codex NDJSON: each line is `{type, payload, timestamp}`. Two-level dispatch on
23	/// `(type, payload.type)`. `token_count` events are dropped (no DTO field for tokens).
24	@Component
25	public class CodexFormat implements TranscriptFormat {
26	
27	    private static final String NAME = "codex-ndjson";
28	    private static final Pattern APPLY_PATCH_HEADER =
29	            Pattern.compile("\\*\\*\\* (Add|Update|Delete) File: (.+)");
30	
31	    private final ObjectMapper objectMapper = new ObjectMapper();
32	
33	    @Override public String name() { return NAME; }
34	    @Override public int priority() { return 60; }
35	
36	    @Override
