38	        for (String line : raw.split("\\R")) {
39	            String t = line.trim();
40	            if (t.isEmpty()) continue;
41	            try {
42	                JsonNode n = objectMapper.readTree(t);
43	                if (!n.isObject() || !n.has("type") || !n.has("payload")) continue;
44	                String type = n.get("type").asText();
45	                if (type.equals("session_meta") || type.equals("response_item")
46	                        || type.equals("event_msg") || type.equals("turn_context")) {
47	                    return true;
48	                }
49	            } catch (Exception e) {
50	                continue;
51	            }
52	        }
53	        return false;
54	    }
