@Component
public class TranscriptGitDiffer {
    private final CheckpointGitReader gitReader;

    public TranscriptGitDiffer(CheckpointGitReader gitReader) {
        this.gitReader = gitReader;
    }

    public void enrich(NormalizedTranscriptDTO dto, Long repoId, String commitSha) {
        if (dto == null || dto.getFileChanges() == null || dto.getFileChanges().isEmpty()) return;
        if (commitSha == null || commitSha.isEmpty()) return;

        String parentSha = gitReader.getParentCommitSha(repoId, commitSha).orElse(null);
        String projectRoot = dto.getProjectRoot();
        List<TranscriptMessageViewDTO> messages = dto.getMessages();
        if (messages == null) return;

        // For each file in fileChanges, build a diff and attach to the last message
        // that touched it.
        for (TranscriptFileChangeSummaryDTO fc : dto.getFileChanges()) {
            String treePath = fc.getFile();
            if (treePath == null || treePath.isEmpty()) continue;
            if (alreadyHasDiff(messages, treePath)) continue;  // OpenCode-style: skip

            String gitRelPath = resolveGitPath(dto, treePath, projectRoot);
            if (gitRelPath == null) continue;

            String after = gitReader.getFileContent(repoId, commitSha, gitRelPath).orElse(null);
            if (after == null) continue;

            String before = parentSha != null
                    ? gitReader.getFileContent(repoId, parentSha, gitRelPath).orElse("")
                    : "";

            TranscriptFileDiffDTO diff = new TranscriptFileDiffDTO();
            diff.setFile(treePath);
            diff.setBefore(before);
            diff.setAfter(after);
            diff.setAdditions(fc.getAdditions() != null ? fc.getAdditions() : 0);
            diff.setDeletions(fc.getDeletions() != null ? fc.getDeletions() : 0);

            // Attach to the last message with a tool that targets this file
            attachToLastMessage(messages, treePath, diff, projectRoot);
        }
    }

    private boolean alreadyHasDiff(List<TranscriptMessageViewDTO> messages, String file) {
        for (TranscriptMessageViewDTO m : messages) {
            if (m.getDiffs() != null) {
                for (TranscriptFileDiffDTO d : m.getDiffs()) {
                    if (file.equals(d.getFile())) return true;
                }
            }
        }
        return false;
    }

    private String resolveGitPath(NormalizedTranscriptDTO dto, String treePath, String projectRoot) {
        // First: try to find a tool with a raw path that maps to this tree path
        for (TranscriptMessageViewDTO m : dto.getMessages() != null ? dto.getMessages() : List.<TranscriptMessageViewDTO>of()) {
            if (m.getTools() == null) continue;
            for (TranscriptToolUseDTO t : m.getTools()) {
                String raw = FilePathExtractor.extract(t.getInput());
                if (raw == null) continue;
                if (matchesTreePath(raw, treePath, projectRoot)) {
                    return toGitRelativePath(raw, projectRoot, treePath);
                }
            }
        }
        // Fallback: assume tree path is the git-relative path (OpenCode case where tree path is already relative)
        return treePath;
    }

    private boolean matchesTreePath(String raw, String tree, String projectRoot) {
        String stripped = stripProjectRoot(raw, projectRoot);
        return stripped.equals(tree) || raw.equals(tree) || raw.endsWith("/" + tree);
    }

    private String toGitRelativePath(String raw, String projectRoot, String treePath) {
        // If raw starts with projectRoot + "/", strip it
        if (projectRoot != null && !projectRoot.isEmpty()) {
            String norm = raw.replace('\\', '/');
            String root = projectRoot.replace('\\', '/').replaceAll("/$", "");
            if (norm.startsWith(root + "/")) {
                return norm.substring(root.length() + 1);
            }
        }
        // Best effort: use the tree path (assume cwd = git root)
        return treePath;
    }

    private String stripProjectRoot(String filePath, String projectRoot) {
        if (projectRoot == null || projectRoot.isEmpty()) return filePath;
        String normalized = filePath.replace('\\', '/');
        String root = projectRoot.replace('\\', '/').replaceAll("/$", "");
        if (normalized.startsWith(root + "/")) {
            return normalized.substring(root.length() 1);
        }
        return filePath;
    }

    private void attachToLastMessage(List<TranscriptMessageViewDTO> messages, String treePath,
                                     TranscriptFileDiffDTO diff, String projectRoot) {
        for (int i = messages.size() - 1; i >= 0; i--) {
            TranscriptMessageViewDTO m = messages.get(i);
            if (m.getTools() == null) continue;
            for (TranscriptToolUseDTO t : m.getTools()) {
                String raw = FilePathExtractor.extract(t.getInput());
                if (raw != null && matchesTreePath(raw, treePath, projectRoot)) {
                    if (m.getDiffs() == null) m.setDiffs(new ArrayList<>());
                    m.getDiffs().add(diff);
                    return;
                }
            }
        }
    }
}
